export const getArgDescription = (cmd: StacktapeCommand, argName: string): string | undefined => {
  const argSchema = commandDefinitions[cmd].args[argName];
  if (!argSchema) return undefined;
  return getSchemaDescription(argSchema as z.ZodType);
};

if (isAgentMode()) {
    if (!args.secretName) {
      throw new ExpectedError('CLI', 'Missing required flag: --secretName', 'Provide --secretName <name>');
    }
    secretName = args.secretName;
  } else {
    secretName = await tuiManager.promptText({
      message: 'Secret name:',
      description: '(name of the AWS Secrets Manager secret to delete)'
    });
  }

