export const getCommandInfo = (cmd: StacktapeCommand) => {
  const def = commandDefinitions[cmd];
  return {
    description: def.description,
    args: Object.fromEntries(Object.keys(def.args).map((argName) => [argName, getArgInfo(cmd, argName)]))
  };
};

